#include<bits/stdc++.h>
using namespace std;
int n,k,b[50010],dis[2500010];
bool vis[2500010],s[101][101];
deque<int> q;
void update(int u,int v,int w)
{
    if(dis[v])
    {
        return;
    }
    if(w==0)
    {
        dis[v]=dis[u];
        q.push_front(v);
    }
    else
    {
        dis[v]=dis[u]+w;
        q.push_back(v);
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    for(int i=1;i<=k;i++)
    {
        for(int j=1;j<=k;j++)
        {
            char ch;
            cin>>ch;
            s[i][j]=ch-'0';
        }
    }
    dis[1]=1;
    q.push_back(1);
    while(!q.empty())
    {
        int t=q.front();
        q.pop_front();
        int tx=(t-1)/n,ty=(t-1)%n+1;
        if(t<=n)
        {
            update(t,b[t]*n+t,0);
            continue;
        }
        if(ty>1)
        {
            update(t,t-1,1);
        }
        if(ty<n)
        {
            update(t,t+1,1);
        }
        if(s[tx][b[ty]])
        {
            update(t,ty,0);
        }
    }
    printf("%d",dis[n]-1);
    return 0;
}
